  ('social-worker-moex-01781', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於同性雙親養育子女的狀況，下列何者與研究發現不一致？', '["同性雙親教養的孩子，長大後性取向為同性戀或雙性戀的比例，不會比異性雙親教養的孩子高", "同性雙親養育的孩子與一般異性雙親家庭長大的孩子，沒有心理或適應上的差異", "同性雙親養育子女的經驗與異性雙親完全不同", "由於偏見持續存在，同性雙親養育的孩子，成長過程要面對的重要議題是羞辱"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "0f97a01c1698", "answer_pdf_sha1": "501bbd54e4d6", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
