  ('social-worker-moex-01783', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '兒童貧窮引起眾多關注，貧窮對於兒童發展的影響，下列敘述何者錯誤？', '["缺乏經濟資源，貧窮的家庭兒童容易經驗到同齡社群排擠", "文化貧窮是兒童成長的主要風險", "經濟困窘、罹患憂鬱症的雙親，社區資源與社會支持決定能否提升雙親照顧子女功能", "弱勢族群父母為了不希望孩子落入貧窮，對子女的學習表現期待較高"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "0f97a01c1698", "answer_pdf_sha1": "501bbd54e4d6", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
